16	// TestServerStatePruneDropsPhantomsKeepsRealProjects seeds a state file with
17	// 10 real project entries (non-/tmp paths) and 100 phantom test-dir entries,
18	// runs `ddx server state prune`, and asserts:
19	//   - 10 entries remain in the state file (all real)
20	//   - A backup file exists containing the original 110 entries
21	//   - Exit code is 0 and summary is printed
22	func TestServerStatePruneDropsPhantomsKeepsRealProjects(t *testing.T) {
23		tmp := t.TempDir()
24		statePath := filepath.Join(tmp, "server-state.json")
25	
26		now := time.Now().UTC().Format(time.RFC3339)
27		projects := make([]map[string]any, 0, 110)
28		for i := 0; i < 10; i++ {
29			projects = append(projects, map[string]any{
30				"id":            "proj-real-" + strconv.Itoa(i),
31				"name":          "real",
32				"path":          "/home/user/projects/real-" + strconv.Itoa(i),
33				"registered_at": now,
34				"last_seen":     now,
35			})
36		}
37		for i := 0; i < 100; i++ {
38			projects = append(projects, map[string]any{
39				"id":            "proj-fake-" + strconv.Itoa(i),
40				"name":          "001",
41				"path":          "/tmp/TestFooBar" + strconv.Itoa(i) + "/001",
42				"registered_at": now,
43				"last_seen":     now,
44			})
45		}
46		state := map[string]any{
47			"schema_version": "1",
48			"node": map[string]any{
49				"name": "test-node", "id": "node-test",
50				"started_at": now, "last_seen": now,
51			},
52			"projects": projects,
53		}
54		data, err := json.MarshalIndent(state, "", "  ")
55		if err != nil {
56			t.Fatal(err)
57		}
58		if err := os.WriteFile(statePath, data, 0o600); err != nil {
59			t.Fatal(err)
60		}
61	
62		// Build and execute the CLI command.
63		f := NewCommandFactory(tmp)
64		root := f.newServerStateCommand()
65		var out bytes.Buffer
66		root.SetOut(&out)
67		root.SetErr(&out)
68		root.SetArgs([]string{"prune", "--state", statePath})
69		if err := root.Execute(); err != nil {
70			t.Fatalf("prune returned error: %v; output: %s", err, out.String())
71		}
72	
73		summary := out.String()
74		if !strings.Contains(summary, "Pruned 100 of 110 entries (10 kept)") {
75			t.Errorf("unexpected summary: %q", summary)
76		}
77		if !strings.Contains(summary, "Backup written to") {
78			t.Errorf("expected backup file path in summary, got %q", summary)
79		}
80	
81		// Verify the state file now has 10 entries.
82		final, err := os.ReadFile(statePath)
83		if err != nil {
84			t.Fatal(err)
85		}
86		var finalState struct {
87			Projects []map[string]any `json:"projects"`
88		}
89		if err := json.Unmarshal(final, &finalState); err != nil {
90			t.Fatal(err)
91		}
92		if len(finalState.Projects) != 10 {
93			t.Errorf("expected 10 projects after prune, got %d", len(finalState.Projects))
94		}
95		for _, p := range finalState.Projects {
96			path, _ := p["path"].(string)
97			if strings.HasPrefix(path, "/tmp/") {
98				t.Errorf("unexpected /tmp/ path survived prune: %s", path)
99			}
100		}
101	
102		// Verify a backup file exists with all 110 entries.
103		entries, err := os.ReadDir(tmp)
104		if err != nil {
105			t.Fatal(err)
106		}
107		backupFound := false
108		for _, e := range entries {
109			if !strings.HasPrefix(e.Name(), "server-state.json.bak-") {
110				continue
111			}
112			backupFound = true
113			backupData, err := os.ReadFile(filepath.Join(tmp, e.Name()))
114			if err != nil {
115				t.Fatal(err)
116			}
117			var backup struct {
118				Projects []map[string]any `json:"projects"`
119			}
120			if err := json.Unmarshal(backupData, &backup); err != nil {
121				t.Fatal(err)
122			}
123			if len(backup.Projects) != 110 {
124				t.Errorf("expected backup to contain 110 entries, got %d", len(backup.Projects))
125			}
126		}
127		if !backupFound {
128			t.Error("expected backup file (*.bak-*) to exist in state dir")
129		}
130	}
