3	// Lint test for ddx-15f7ee0b Fix A: every test file in this package (and
4	// adjacent directories that wire up ServerState) that constructs a server or
5	// loads a ServerState must point the state directory at an isolated location.
6	// Tests that skip this leak phantom project entries into the developer's real
7	// ~/.local/share/ddx/server-state.json.
8	//
9	// The check is intentionally conservative: a function that calls any of the
10	// "constructor" set below must also invoke at least one of the "isolation"
11	// set. Adding a new helper that internally isolates XDG_DATA_HOME is the
12	// preferred way to keep this passing.
13	
14	import (
15		"go/ast"
16		"go/parser"
17		"go/token"
18		"io/fs"
19		"path/filepath"
20		"strings"
21		"testing"
22	)
23	
24	// constructorNames are function calls that build a server or directly load a
25	// ServerState. Any test that touches one of these must also pick up isolation.
26	// Entries without a "pkg." prefix match only package-local calls; entries like
27	// "server.New" match explicit cross-package qualified references.
28	var constructorNames = map[string]bool{
29		"New":               true,
30		"server.New":        true,
31		"loadServerState":   true,
32		"ListenAndServe":    true,
33		"ListenAndServeTLS": true,
34	}
35	
36	// isolationHelpers are helpers (defined in this package or adjacent test
37	// helpers) that set XDG_DATA_HOME before any server is created. A call to
38	// any of them satisfies the lint rule.
39	var isolationHelpers = map[string]bool{
40		"setupTestDir":               true,
41		"setupNodeTestDir":           true,
42		"setupProcessMetricsTestDir": true,
43		"setupDocTestDir":            true,
44		"setupExecTestDir":           true,
45		"setupGitTestDir":            true,
46		"setupProjectWithBeads":      true,
47		"setupBeadLookupFixture":     true,
48		"BuildBeadFixture":           true,
49	}
50	
51	// TestTestsIsolateStateDir walks the Go test files in the server package and
52	// perf sub-package, and asserts that every test (or benchmark) function that
53	// wires up a server also isolates XDG_DATA_HOME. See ddx-15f7ee0b Fix A.
54	func TestTestsIsolateStateDir(t *testing.T) {
55		err := filepath.WalkDir(".", func(path string, d fs.DirEntry, err error) error {
56			if err != nil {
57				return err
58			}
59			if d.IsDir() {
60				switch d.Name() {
61				case "frontend", "node_modules", ".svelte-kit", "build":
62					return filepath.SkipDir
63				default:
64					return nil
65				}
66			}
67			if strings.HasSuffix(d.Name(), "_test.go") {
68				lintTestFile(t, path)
69			}
70			return nil
71		})
72		if err != nil {
73			t.Fatalf("walk server tests: %v", err)
74		}
75	}
