77	func lintTestFile(t *testing.T, path string) {
78		t.Helper()
79		fset := token.NewFileSet()
80		file, err := parser.ParseFile(fset, path, nil, parser.SkipObjectResolution)
81		if err != nil {
82			t.Fatalf("parse %s: %v", path, err)
83		}
84	
85		// Skip the lint test file itself — it is allowed to reference constructor
86		// names inside string maps without wiring up a server.
87		if strings.HasSuffix(path, "/test_isolation_lint_test.go") {
88			return
89		}
90	
91		for _, decl := range file.Decls {
92			fn, ok := decl.(*ast.FuncDecl)
93			if !ok || fn.Body == nil {
94				continue
95			}
96			// Only audit functions that could contain test code — Test*, Benchmark*,
97			// or helpers used by such functions. For simplicity, audit all fns in
98			// _test.go files. Helpers that unconditionally call setupTestDir etc.
99			// will pass trivially.
100			hasCtor := false
101			hasIso := false
102			ast.Inspect(fn.Body, func(n ast.Node) bool {
103				call, ok := n.(*ast.CallExpr)
104				if !ok {
105					return true
106				}
107				name := callName(call.Fun)
108				if constructorNames[name] {
109					hasCtor = true
110				}
111				if isolationHelpers[name] {
112					hasIso = true
113				}
114				// Detect raw XDG_DATA_HOME sets: any call with a first arg that is
115				// the string literal "XDG_DATA_HOME".
116				if name == "Setenv" || name == "t.Setenv" {
117					// argList: check any arg is "XDG_DATA_HOME"
118					for _, a := range call.Args {
119						if lit, ok := a.(*ast.BasicLit); ok && lit.Kind == token.STRING {
120							if strings.Trim(lit.Value, "`\"") == "XDG_DATA_HOME" {
121								hasIso = true
122							}
123						}
124					}
125				}
126				return true
127			})
128	
129			if hasCtor && !hasIso {
130				t.Errorf("%s: function %s constructs a server without isolating XDG_DATA_HOME — call setupTestDir/etc. or t.Setenv(\"XDG_DATA_HOME\", ...) before building the server (ddx-15f7ee0b Fix A)",
131					path, fn.Name.Name)
132			}
133		}
134	}
135	
136	// callName returns one of three things:
137	//   - For `Foo(...)`:         "Foo"
138	//   - For `pkg.Foo(...)`:     "pkg.Foo"
139	//   - For `t.Setenv(...)`:    "Setenv"  (receiver is a local identifier, not
140	//     a package — we only add the prefix when the
141	//     receiver looks like a package name, i.e.
142	//     lowercase and short; this is a heuristic.)
143	//
144	// Having qualified names lets the constructor list distinguish server.New
145	// from handler.New without false positives.
146	func callName(fn ast.Expr) string {
147		switch v := fn.(type) {
148		case *ast.Ident:
149			return v.Name
150		case *ast.SelectorExpr:
151			if pkg, ok := v.X.(*ast.Ident); ok {
152				// Heuristic: treat short lowercase identifiers as package names.
153				// Receivers like `t`, `srv`, `w` fall through — we still want
154				// Setenv to match for `t.Setenv(...)`. The Setenv match is
155				// special-cased by the lint body; the selector branch here just
156				// carries the package-qualified form when it looks right.
157				if looksLikePackageName(pkg.Name) {
158					return pkg.Name + "." + v.Sel.Name
159				}
160			}
161			return v.Sel.Name
162		}
163		return ""
164	}
165	
166	// looksLikePackageName is a heuristic for callName: longer-than-2 lowercase
167	// identifiers are treated as package-like (so "server.New" is distinguished
168	// from "srv.Shutdown"). Receivers like t, s, srv, b, tb return false.
169	func looksLikePackageName(s string) bool {
170		if len(s) < 3 {
171			return false
172		}
173		for _, r := range s {
174			if r < 'a' || r > 'z' {
175				return false
176			}
177		}
178		// Reject common local-variable names that happen to be lowercase words.
179		switch s {
180		case "srv", "tb", "ctx", "err", "req", "res":
181			return false
182		}
183		return true
184	}
