186	// TestTestIsolationLintCatchesBadCase is a meta-test: it feeds the linter a
187	// synthetic "bad" file and asserts the linter flags it. Covers the
188	// "disallowed-pattern" arm of ddx-15f7ee0b Fix A.
189	func TestTestIsolationLintCatchesBadCase(t *testing.T) {
190		badSource := `package server
191	
192	import "testing"
193	
194	func TestBadlyIsolatedExample(t *testing.T) {
195		srv := New(":0", "/tmp/ignored")
196		_ = srv
197	}
198	`
199		goodSource := `package server
200	
201	import "testing"
202	
203	func TestProperlyIsolatedExample(t *testing.T) {
204		t.Setenv("XDG_DATA_HOME", t.TempDir())
205		srv := New(":0", "/tmp/ignored")
206		_ = srv
207	}
208	`
209		if got := lintSourceString(badSource); got == nil {
210			t.Error("expected bad source to be flagged by lint, got nil")
211		}
212		if got := lintSourceString(goodSource); got != nil {
213			t.Errorf("expected good source to pass lint, got error: %v", got)
214		}
215	}
