217	// lintSourceString runs the same AST walk on an in-memory source string and
218	// returns a non-nil error if the lint would have failed. Used by the meta-test.
219	func lintSourceString(src string) error {
220		fset := token.NewFileSet()
221		file, err := parser.ParseFile(fset, "synthetic.go", src, parser.SkipObjectResolution)
222		if err != nil {
223			return err
224		}
225		for _, decl := range file.Decls {
226			fn, ok := decl.(*ast.FuncDecl)
227			if !ok || fn.Body == nil {
228				continue
229			}
230			hasCtor := false
231			hasIso := false
232			ast.Inspect(fn.Body, func(n ast.Node) bool {
233				call, ok := n.(*ast.CallExpr)
234				if !ok {
235					return true
236				}
237				name := callName(call.Fun)
238				if constructorNames[name] {
239					hasCtor = true
240				}
241				if isolationHelpers[name] {
242					hasIso = true
243				}
244				if name == "Setenv" {
245					for _, a := range call.Args {
246						if lit, ok := a.(*ast.BasicLit); ok && lit.Kind == token.STRING {
247							if strings.Trim(lit.Value, "`\"") == "XDG_DATA_HOME" {
248								hasIso = true
249							}
250						}
251					}
252				}
253				return true
254			})
255			if hasCtor && !hasIso {
256				return &lintErr{msg: fn.Name.Name + " constructs server without isolation"}
257			}
258		}
259		return nil
260	}
