53	// GetBeadSnapshots implements ddxgraphql.StateProvider.
54	//
55	// When projectID is non-empty this delegates to GetBeadSnapshotsForProject so
56	// the resolver path opens exactly one project's store; a scoped query never
57	// pays the N-project scan cost (ddx-9ce6842a Part 2 step 1). When projectID is
58	// empty every registered project is scanned — that is still O(projects) by
59	// necessity, but each project's bead.Store receives a pushed-down filter so
60	// non-matching beads are never materialized as BeadSnapshot values.
61	func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
62		if projectID != "" {
63			return s.GetBeadSnapshotsForProject(projectID, status, label, search)
64		}
65		projects := s.GetProjects()
66		pred := beadFilterPredicate(status, label, search)
67		var result []ddxgraphql.BeadSnapshot
68		for _, proj := range projects {
69			result = append(result, s.beadSnapshotsForProjectEntry(proj, pred)...)
70		}
71		return result
72	}
